import anthropic
import json

client = anthropic.Anthropic()

REACT_SYSTEM = """
You are a research assistant. Solve tasks step by step.

Before each action write:
Thought: <what you know | what you still need | chosen tool and why>

When you have a complete answer, call task_complete.
When the task is impossible, call task_failed.
Never stop without calling one of those two tools.
"""

def search(query: str) -> str:
    return json.dumps({"results": [
        {"title": "Paris facts", "snippet": "Paris has 2.1M residents and 30M annual visitors."},
    ]})

TOOLS = [
    {
        "name": "search",
        "description": "Search for information.",
        "input_schema": {
            "type": "object",
            "properties": {"query": {"type": "string"}},
            "required": ["query"],
        },
    },
    {
        "name": "task_complete",
        "description": "Call when the task is fully solved.",
        "input_schema": {
            "type": "object",
            "properties": {"answer": {"type": "string"}},
            "required": ["answer"],
        },
    },
    {
        "name": "task_failed",
        "description": "Call when the task cannot be completed.",
        "input_schema": {
            "type": "object",
            "properties": {"reason": {"type": "string"}},
            "required": ["reason"],
        },
    },
]

DISPATCH = {"search": search}

def run_react(user_message: str, max_iterations: int = 15) -> dict:
    messages = [{"role": "user", "content": user_message}]
    status = "running"
    result = None

    for iteration in range(1, max_iterations + 1):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            system=REACT_SYSTEM,
            tools=TOOLS,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": resp.content})

        tool_calls = [b for b in resp.content if b.type == "tool_use"]

        # Check for control tools first
        for block in tool_calls:
            if block.name == "task_complete":
                return {"status": "complete", "answer": block.input["answer"], "iterations": iteration}
            if block.name == "task_failed":
                return {"status": "failed", "reason": block.input["reason"], "iterations": iteration}

        # No tool calls — stuck (model forgot to call task_complete)
        if not tool_calls:
            final_text = next((b.text for b in resp.content if b.type == "text"), "")
            return {"status": "stuck", "partial_text": final_text, "iterations": iteration}

        # REPEAT: dispatch tool calls and continue the loop
        tool_results = []
        for block in tool_calls:
            fn = DISPATCH.get(block.name)
            result_str = fn(**block.input) if fn else json.dumps({"error": f"Unknown tool: {block.name}"})
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": result_str,
            })
        messages.append({"role": "user", "content": tool_results})

    return {"status": "max_iterations", "iterations": max_iterations}

outcome = run_react("How many people live in Paris?")
print(f"Status: {outcome['status']}")
if outcome["status"] == "complete":
    print(f"Answer: {outcome['answer']}")
print(f"Iterations used: {outcome['iterations']}")

import hashlib, json

class LoopGuard:
    """
    Detects repeated tool calls and stalled loops.
    Raises LoopGuardError when a stuck pattern is detected.
    """

    class LoopGuardError(Exception):
        pass

    def __init__(self, max_repeats: int = 3, stall_window: int = 4):
        self.max_repeats = max_repeats
        self.stall_window = stall_window
        self._call_counts: dict[str, int] = {}
        self._recent_results: list[str] = []

    def record_call(self, tool_name: str, arguments: dict):
        key = hashlib.md5(
            json.dumps({"tool": tool_name, "args": arguments}, sort_keys=True).encode()
        ).hexdigest()
        self._call_counts[key] = self._call_counts.get(key, 0) + 1
        if self._call_counts[key] >= self.max_repeats:
            raise LoopGuard.LoopGuardError(
                f"Tool '{tool_name}' called {self.max_repeats}x with same args — loop detected."
            )

    def record_result(self, result: str):
        self._recent_results.append(result[:100])   # fingerprint
        if len(self._recent_results) > self.stall_window:
            self._recent_results = self._recent_results[-self.stall_window:]
        if len(set(self._recent_results)) == 1 and len(self._recent_results) == self.stall_window:
            raise LoopGuard.LoopGuardError(
                f"Same observation for {self.stall_window} consecutive rounds — loop stalled."
            )

