SOFT_CAP = 10   # at this point, inject a "please conclude now" message
HARD_CAP = 15   # at this point, abort unconditionally

CONCLUDE_NOW = (
    "You have used many iterations. "
    "Based on what you know so far, provide the best answer you can "
    "and call task_complete. Do not call any more tool lookups."
)

def run_with_tiered_budget(client, system, tools, dispatch, user_msg):
    messages = [{"role": "user", "content": user_msg}]

    for iteration in range(1, HARD_CAP + 1):
        # At soft cap, inject a conclude-now instruction
        if iteration == SOFT_CAP:
            messages.append({"role": "user", "content": CONCLUDE_NOW})

        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            system=system,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": resp.content})

        tool_calls = [b for b in resp.content if b.type == "tool_use"]

        for block in tool_calls:
            if block.name == "task_complete":
                return {"status": "complete", "answer": block.input["answer"], "iterations": iteration}
            if block.name == "task_failed":
                return {"status": "failed", "reason": block.input["reason"], "iterations": iteration}

        if not tool_calls:
            text = next((b.text for b in resp.content if b.type == "text"), "")
            return {"status": "stuck", "partial": text, "iterations": iteration}

        results = []
        for block in tool_calls:
            fn = dispatch.get(block.name)
            result = fn(**block.input) if fn else f"Unknown tool: {block.name}"
            results.append({"type": "tool_result", "tool_use_id": block.id, "content": str(result)})
        messages.append({"role": "user", "content": results})

    return {"status": "max_iterations", "iterations": HARD_CAP}
